param(
  [string]$OutFile = "cmd/vantare/supabase_build.go"
)

$url = $env:VANTARE_SUPABASE_URL
$key = $env:VANTARE_SUPABASE_ANON_KEY

if (-not $url -and -not $key) {
  # No Supabase config to embed. Remove any stale generated file.
  if (Test-Path -LiteralPath $OutFile) {
    Remove-Item -LiteralPath $OutFile -Force
  }
  exit 0
}

# Encode as base64 so the values survive PowerShell string interpolation
# without escaping issues. The Go init() decodes them at startup.
$b64Url = [Convert]::ToBase64String([Text.Encoding]::UTF8.GetBytes($url))
$b64Key = [Convert]::ToBase64String([Text.Encoding]::UTF8.GetBytes($key))

$content = @"
// Code generated by build tool. DO NOT EDIT.

package main

import "encoding/base64"

func init() {
  if decoded, err := base64.StdEncoding.DecodeString("$b64Url"); err == nil {
    supabaseURL = string(decoded)
  }
  if decoded, err := base64.StdEncoding.DecodeString("$b64Key"); err == nil {
    supabaseAnonKey = string(decoded)
  }
}
"@

Set-Content -NoNewline -LiteralPath $OutFile -Value $content
